#include <iostream>
#include <string>
using namespace std;
int a[26],b[26];
int main()
{
    string s,t;
    cin>>s>>t;
    for (int i=0;i<s.size();i++)a[s[i]-'a']++;
    for (int i=0;i<t.size();i++)b[t[i]-'a']++;
    for (int i=0;i<26;i++)
    {
        a[i]=b[i]=min(a[i],b[i]);
    }
    int ans=0;
    for (int i=0;i<26;i++)
    {
        ans+=a[i];
    }
    cout<<ans;
    return 0;
}
